from enum import Enum

class Likelihood(Enum):
    RARE            = 1   # < 1% probability in a 12-month window
    UNLIKELY        = 2   # 1–10%
    POSSIBLE        = 3   # 10–50%
    LIKELY          = 4   # 50–90%
    ALMOST_CERTAIN  = 5   # > 90%

# AI-specific calibration anchors — translates observed metrics into ratings
AI_LIKELIHOOD_ANCHORS = {
    "hallucination_rate": {
        # fraction of responses with ungrounded assertions, measured by eval suite
        Likelihood.RARE:           (0.000, 0.005),
        Likelihood.UNLIKELY:       (0.005, 0.02),
        Likelihood.POSSIBLE:       (0.02,  0.10),
        Likelihood.LIKELY:         (0.10,  0.30),
        Likelihood.ALMOST_CERTAIN: (0.30,  1.00),
    },
    "pii_scan_hit_rate": {
        # fraction of responses triggering the PII output scanner per day
        Likelihood.RARE:           (0.000, 0.0001),
        Likelihood.UNLIKELY:       (0.0001, 0.001),
        Likelihood.POSSIBLE:       (0.001, 0.01),
        Likelihood.LIKELY:         (0.01,  0.05),
        Likelihood.ALMOST_CERTAIN: (0.05,  1.00),
    },
    "model_drift_eval_degradation": {
        # percentage-point drop in eval suite score vs baseline
        Likelihood.RARE:           (0,  1),
        Likelihood.UNLIKELY:       (1,  3),
        Likelihood.POSSIBLE:       (3,  10),
        Likelihood.LIKELY:         (10, 20),
        Likelihood.ALMOST_CERTAIN: (20, 100),
    },
}


def calibrate_likelihood(metric: str, observed_value: float) -> Likelihood:
    """Map an observed metric value to a calibrated likelihood rating."""
    anchors = AI_LIKELIHOOD_ANCHORS.get(metric)
    if not anchors:
        raise ValueError(f"Unknown metric: {metric}")
    for level, (lo, hi) in anchors.items():
        if lo <= observed_value < hi:
            return level
    return Likelihood.ALMOST_CERTAIN  # above all ranges

from dataclasses import dataclass, field
from typing import Optional

@dataclass
class ControlEffect:
    description: str
    # Likelihood reduction: fraction removed from likelihood rating (0.0–1.0)
    likelihood_reduction: float = 0.0
    # Impact reduction: fraction removed from impact rating (0.0–1.0)
    impact_reduction: float = 0.0

    def __post_init__(self):
        if not (0.0 <= self.likelihood_reduction <= 1.0):
            raise ValueError("likelihood_reduction must be 0.0–1.0")
        if not (0.0 <= self.impact_reduction <= 1.0):
            raise ValueError("impact_reduction must be 0.0–1.0")


class RiskScorer:
    """
    Scores a risk across inherent and residual dimensions.
    Treats likelihood and impact as separate axes, not a single multiplied score,
    to allow controls that reduce one dimension but not the other.
    """

    def __init__(self, likelihood: int, impact: int):
        assert 1 <= likelihood <= 5 and 1 <= impact <= 5
        self.base_likelihood = likelihood
        self.base_impact = impact

    @property
    def inherent_score(self) -> int:
        return self.base_likelihood * self.base_impact

    def apply_controls(self, controls: list[ControlEffect]):
        # Diminishing-returns compounding per axis
        lr = 0.0
        ir = 0.0
        for c in controls:
            lr = lr + c.likelihood_reduction * (1 - lr)
            ir = ir + c.impact_reduction     * (1 - ir)

        residual_l = max(1, round(self.base_likelihood * (1 - lr)))
        residual_i = max(1, round(self.base_impact     * (1 - ir)))
        return residual_l, residual_i

    def residual_score(self, controls: list[ControlEffect]) -> int:
        l, i = self.apply_controls(controls)
        return l * i

    @staticmethod
    def rating(score: int) -> str:
        if score <= 5:   return "low"
        if score <= 9:   return "medium"
        if score <= 15:  return "high"
        return "critical"
